class FieldType(IntEnum):
    BASE = 0
    NORMAL = 1
    OBSTACLE_SLOW = 2
    OBSTACLE = 3
    POWERUP = 4
    WALL = 5
    EMPTY = 6
    
    def movement_cost(self) -> int:
        match self:
            case FieldType.BASE | FieldType.NORMAL | FieldType.OBSTACLE | FieldType.POWERUP:
                return 1
            case FieldType.OBSTACLE_SLOW:
                return 2
            case _:
                return 1000

    def spike_damage(self) -> int:
        return 10 if self == FieldType.OBSTACLE else 0


class Status(IntEnum):
    Normal = 0
    Fatigue = 1
    Frozen = 2
    Dizzy = 3


class ItemType(IntEnum):
    NONE = 0
    Healing = 1
    Movement = 2
    Defense = 3
    Utility = 4
    CrowdControl = 5
    Attack = 6


