@dataclass
class Map:
    x: int
    y: int
    name: str
    grid: list[FieldInfo]
    maxMoveDistance: int
    graph: nx.DiGraph = field(init=False)

    def __post_init__(self):
        self.graph = nx.DiGraph()
        self.graph.add_nodes_from(range(len(self.grid)))
        for cell in self.grid:
            self._findAllPossible(cell)
            
    def pair_to_index(self, x: int, y: int) -> int:
        return x * self.y + y
    
    def index_to_pair(self, index: int) -> tuple[int, int]:
        return (index // self.y, index % self.y)

    def get_cell(self, x: int, y: int) -> Optional[FieldInfo]:
        if self._checkCoords(Position(x, y)):
            return self.grid[self.pair_to_index(x, y)]
        return None
        
    def _checkCoords(self, pos: Position):
        return pos.x >= 0 and pos.x < self.x and pos.y >= 0 and pos.y < self.y
    
    def _movement_cost(self, pos: Position) -> int:
        field = self.get_cell(pos.x, pos.y)
        return field.field_type.movement_cost() if self._checkCoords(pos) and not field.is_occupied() else 1000
    
    def _findAllPossible(self, field: FieldInfo):
        field_pos = field.position
        if field_pos is None:
            return
        dirs = [(0, 1), (1, 0), (0, -1), (-1, 0)]
        for d in dirs:
            total_spike_damage = self.get_cell(field_pos.x, field_pos.y).field_type.spike_damage()
            movementRemaining = self.maxMoveDistance
            if field.field_type == FieldType.OBSTACLE_SLOW:
                movementRemaining -= 1
            cur_pos = Position(field_pos.x + d[0], field_pos.y + d[1])
            movementRemaining -= self._movement_cost(cur_pos)
            while movementRemaining >= 0:
                total_spike_damage += self.get_cell(cur_pos.x, cur_pos.y).field_type.spike_damage()
                self.graph.add_edge(
                    self.pair_to_index(field_pos.x, field_pos.y),
                    self.pair_to_index(cur_pos.x, cur_pos.y),
                    weight = total_spike_damage
                )
                cur_pos = Position(cur_pos.x + d[0], cur_pos.y + d[1])
                movementRemaining -= self._movement_cost(cur_pos)
            

@dataclass
class GameState:
    game_id: str
    state_str: str
    current_turn: int
    players: dict[str, Player]
    map: Map


def _g(d: dict, key: str, default=None):
    v = d.get(key)
    if v is not None:
        return v
    camel = key[0].lower() + key[1:]
    v = d.get(camel)
    if v is not None:
        return v
    return default


def _parse_position(d: Optional[dict]) -> Optional[Position]:
    if not d:
        return None
    return Position(x=_g(d, "X", 0), y=_g(d, "Y", 0))


def _parse_statuses(d: Optional[dict]) -> dict[Status, int]:
    if not d:
        return {}
    out: dict[Status, int] = {}
    for k, v in d.items():
        try:
            out[Status(int(k))] = v
        except (ValueError, KeyError):
            for s in Status:
                if s.name.lower() == str(k).lower():
                    out[s] = v
                    break
    return out


def _parse_item(d: Optional[dict]) -> Optional[Item]:
    if not d:
        return None
    return Item(
        id=_g(d, "Id", 0),
        name=_g(d, "Name", ""),
        uses=_g(d, "Uses"),
        effect=_g(d, "Effect"),
        range=_g(d, "Range"),
        power=_g(d, "Power"),
        duration=_g(d, "Duration"),
        item_type=ItemType(_g(d, "ItemType", 0)),
    )


def _parse_entity(d: Optional[dict]) -> Optional[Entity]:
    if not d:
        return None
    return Entity(
        id=_g(d, "Id", 0),
        name=_g(d, "Name", ""),
        health=_g(d, "Health", 0),
        max_health=_g(d, "MaxHealth", 0),
        attack_power=_g(d, "AttackPower", 0),
        attack_range=_g(d, "AttackRange", 0),
        max_move_distance=_g(d, "MaxMoveDistance", 0),
        position=_parse_position(_g(d, "Position")) or Position(0, 0),
        summoned_by=_g(d, "SummonedByPlayerId"),
        active_statuses=_parse_statuses(_g(d, "ActiveStatuses")),
        x_pattern=d.get("xPattern") or [],
        y_pattern=d.get("yPattern") or [],
    )


def _parse_monster_card(d: Optional[dict]) -> Optional[MonsterCard]:
    if not d:
        return None
    return MonsterCard(
        id=_g(d, "Id", 0),
        name=_g(d, "Name", ""),
        uses=_g(d, "Uses"),
        effect=_g(d, "Effect"),
        power=_g(d, "Power", 0),
        on_cooldown=_g(d, "OnCooldown", False),
        cooldown=_g(d, "Cooldown", 0),
        cooldown_counter=_g(d, "CooldownCounter", 0),
        monster=_parse_entity(_g(d, "Monster")),
    )


def _parse_player(d: Optional[dict]) -> Optional[Player]:
    if not d:
        return None
    return Player(
        id=_g(d, "Id", 0),
        name=_g(d, "Name", ""),
        health=_g(d, "Health", 0),
        max_health=_g(d, "MaxHealth", 100),
        attack_power=_g(d, "AttackPower", 0),
        attack_range=_g(d, "AttackRange", 0),
        max_move_distance=_g(d, "MaxMoveDistance", 0),
        position=_parse_position(_g(d, "Position")) or Position(0, 0),
        summoned_by=_g(d, "SummonedByPlayerId"),
        active_statuses=_parse_statuses(_g(d, "ActiveStatuses")),
        x_pattern=d.get("xPattern") or [],
        y_pattern=d.get("yPattern") or [],
        level=_g(d, "Level", 0),
        xp=_g(d, "Xp", 0),
        inventory=[_parse_item(i) for i in (_g(d, "Inventory") or []) if i],
        cards=[_parse_monster_card(c) for c in (_g(d, "Cards") or []) if c],
        first=bool(_g(d, "First", False)),
    )


def _parse_obstacle(d: Optional[dict]) -> Optional[Obstacle]:
    if not d:
        return None
    return Obstacle(
        type=_g(d, "Type", ""),
        damage=_g(d, "Damage", 0),
        cooldown=_g(d, "Cooldown", 0),
        current_cooldown=_g(d, "CurrentCooldown", 0),
    )


def _parse_field_info(d: dict) -> FieldInfo:
    return FieldInfo(
        position=_parse_position(_g(d, "Position")),
        entity=_parse_entity(_g(d, "Entity")),
        field_type=FieldType(_g(d, "FieldType", 1)),
        owner=_parse_player(_g(d, "Owner")),
        item=_parse_item(_g(d, "Item")),
        monster_card=_parse_monster_card(_g(d, "MonsterCard")),
        obstacle=_parse_obstacle(_g(d, "Obstacle")),
    )


def _parse_map(d: Optional[dict], maxMoveDistance: int) -> Optional[Map]:
    if not d:
        return None
    return Map(
        x=_g(d, "X", 32),
        y=_g(d, "Y", 16),
        name=_g(d, "Name", ""),
        grid=[_parse_field_info(f) for f in (_g(d, "Grid") or [])],
        maxMoveDistance = maxMoveDistance,
    )


def parse_game_state(d: dict) -> GameState:
    players_raw = _g(d, "Players") or {}
    players = {k: p for k, v in players_raw.items() if (p := _parse_player(v))}
    max_move_distance = next(
        (p.max_move_distance for p in players.values()), 
        4
    )
    return GameState(
        game_id=_g(d, "GameId") or _g(d, "Id") or "",
        state_str=_g(d, "GameState", ""),
        current_turn=_g(d, "TurnCounter", 0),
        players=players,
        map=_parse_map(_g(d, "Map"), max_move_distance) or Map(32, 16, "", []),
    )


def parse_action_response(d: dict) -> tuple[Optional[Map], Optional[Player]]:
    player = _parse_player(_g(d, "Player"))
    max_move_distance = player.max_move_distance if player is not None else 4
    
    return (_parse_map(_g(d, "Map"), max_move_distance), player)


