from typing import Optional



MAP_X = 32
MAP_Y = 16
CARDINALS = [(1, 0), (-1, 0), (0, 1), (0, -1)]


def in_bounds(x: int, y: int) -> bool:
    return 0 <= x < MAP_X and 0 <= y < MAP_Y


def tile_at(m: Map, x: int, y: int) -> Optional[FieldInfo]:
    if not in_bounds(x, y):
        return None
    return m.get_cell(x, y)


def manhattan(a: Position, b: Position) -> int:
    return abs(a.x - b.x) + abs(a.y - b.y)


def is_adjacent(a: Position, b: Position) -> bool:
    return manhattan(a, b) == 1


def orthogonal_neighbors(pos: Position) -> list[tuple[int, int]]:
    return [(pos.x + dx, pos.y + dy) for dx, dy in CARDINALS if in_bounds(pos.x + dx, pos.y + dy)]


def nearest_xy(from_pos: Position, candidates: list[tuple[int, int]]) -> Optional[tuple[int, int]]:
    if not candidates:
        return None
    return min(candidates, key=lambda xy: abs(xy[0] - from_pos.x) + abs(xy[1] - from_pos.y))


