from typing import Optional



ICE_CUBE_CARD_NAME = "Card of Ice Cubes"
ITEM_HEAL_NAME = "Kristal života"
ITEM_FREEZE_NAME = "Freeze scroll"
ITEM_DIZZY_NAME = "Dizzy scroll"


def _is_ice_cube_card(c: MonsterCard) -> bool:
    return (c.name or "").strip().lower() == ICE_CUBE_CARD_NAME.lower()


def _is_mage_card(c: MonsterCard) -> bool:
    return not _is_ice_cube_card(c) and (c.power or 0) >= 35


def _is_warrior_card(c: MonsterCard) -> bool:
    return not _is_ice_cube_card(c) and (c.power or 0) < 35


def available_cube_cards(me: Player) -> list[MonsterCard]:
    return [c for c in me.cards
            if _is_ice_cube_card(c) and c.cooldown_counter == 0 and (c.uses or 0) > 0]


def available_warrior_cards(me: Player) -> list[MonsterCard]:
    return [c for c in me.cards
            if _is_warrior_card(c) and c.cooldown_counter == 0 and (c.uses or 0) > 0]


def available_mage_cards(me: Player) -> list[MonsterCard]:
    return [c for c in me.cards
            if _is_mage_card(c) and c.cooldown_counter == 0 and (c.uses or 0) > 0]


def count_cards(me: Player) -> int:
    return len(me.cards or [])


def pick_card_max_uses(cards: list[MonsterCard]) -> Optional[MonsterCard]:
    if not cards:
        return None
    return max(cards, key=lambda c: c.uses or 0)


def find_item_by_name(me: Player, name: str) -> Optional[Item]:
    target = name.strip().lower()
    for it in me.inventory:
        if (it.name or "").strip().lower() == target:
            return it
    return None


def has_status(p: Player, s: Status) -> bool:
    return p.active_statuses.get(s, 0) > 0


def is_fatigued(p: Player) -> bool:
    return has_status(p, Status.Fatigue)


def has_heal(me: Player) -> bool:
    return find_item_by_name(me, ITEM_HEAL_NAME) is not None


def has_freeze(me: Player) -> bool:
    return find_item_by_name(me, ITEM_FREEZE_NAME) is not None


def count_item_by_name(me: Player, name: str) -> int:
    target = name.strip().lower()
    return sum(1 for it in me.inventory if (it.name or "").strip().lower() == target)


def count_freeze(me: Player) -> int:
    return count_item_by_name(me, ITEM_FREEZE_NAME)

def count_heal(me: Player) -> int:
    return count_item_by_name(me, ITEM_HEAL_NAME)


# ===== inlined from bots/engine/helpers/shrink.py =====
SHRINK_SETUP_TURNS = {13, 14, 28, 29, 43, 44}


def shrink_danger_columns_for_turn(turn: int) -> set[int]:
    if turn < 15:
        return set(list(range(0, 3)) + list(range(29, 32)))
    if turn < 30:
        return set(list(range(3, 6)) + list(range(26, 29)))
    return set()


def is_in_bridge_wall_zone(pos: Position) -> bool:
    in_band = (6 <= pos.x <= 12) or (20 <= pos.x <= 27)
    return in_band and (pos.y <= 3 or pos.y >= 12)


def in_shrink_danger(pos: Position, turn: int) -> bool:
    eps = 5
    if turn < 15 and turn >= 15 - eps:
        return pos.x in {0, 1, 2, 29, 30, 31}
    if turn < 30 and turn >= 30 - eps:
        return pos.x in {3, 4, 5, 26, 27, 28}
    if turn < 45 and turn >= 45 - eps:
        return is_in_bridge_wall_zone(pos)
    return False


def filter_safe(reachable: set[tuple[int, int]], turn: int) -> set[tuple[int, int]]:
    if turn >= 45:
        return reachable
    if turn >= 30:
        return {(x, y) for (x, y) in reachable if not is_in_bridge_wall_zone(Position(x, y))}
    danger = shrink_danger_columns_for_turn(turn)
    return {(x, y) for (x, y) in reachable if x not in danger}


