from typing import Iterable, Optional




def iter_cells(m: Map) -> Iterable[tuple[int, int, FieldInfo]]:
    for x in range(MAP_X):
        for y in range(MAP_Y):
            t = m.get_cell(x, y)
            if t is not None:
                yield x, y, t


def find_card_tiles(state: GameState, card_id: Optional[int] = None) -> list[tuple[int, int]]:
    if card_id is not None:
        return [(x, y) for x, y, t in iter_cells(state.map)
                if t.monster_card is not None and t.monster_card.id == card_id]
    return [(x, y) for x, y, t in iter_cells(state.map)
            if t.monster_card is not None and _is_ice_cube_card(t.monster_card)]


def find_item_tiles(state: GameState, item_id: Optional[int] = None,
                    item_name: Optional[str] = None) -> list[tuple[int, int]]:
    if item_name is not None:
        target = item_name.strip().lower()
        return [(x, y) for x, y, t in iter_cells(state.map)
                if t.item is not None and (t.item.name or "").strip().lower() == target]
    if item_id is not None:
        return [(x, y) for x, y, t in iter_cells(state.map)
                if t.item is not None and t.item.id == item_id]
    return []


def find_allied_summons(state: GameState, me: Player) -> list:
    out = []
    for _, _, t in iter_cells(state.map):
        if t.entity and t.entity.summoned_by == me.id:
            out.append(t.entity)
    return out


def adjacent_card_tile(state: GameState, me: Player,
                       ice_cube_only: bool = False) -> Optional[tuple[int, int]]:
    for nx, ny in orthogonal_neighbors(me.position):
        t = tile_at(state.map, nx, ny)
        if not t or t.monster_card is None:
            continue
        if ice_cube_only and not _is_ice_cube_card(t.monster_card):
            continue
        return (nx, ny)
    return None


def adjacent_item_tile(state: GameState, me: Player, item_id: Optional[int] = None,
                       item_name: Optional[str] = None) -> Optional[tuple[int, int]]:
    target_name = item_name.strip().lower() if item_name else None
    for nx, ny in orthogonal_neighbors(me.position):
        t = tile_at(state.map, nx, ny)
        if not t or t.item is None:
            continue
        if target_name is not None:
            if (t.item.name or "").strip().lower() == target_name:
                return (nx, ny)
            continue
        if item_id is not None:
            if t.item.id == item_id:
                return (nx, ny)
            continue
        return (nx, ny)
    return None


# ===== inlined from bots/engine/helpers/movement.py =====
import collections
from typing import Callable, Optional



def bfs_path(state: GameState, start: tuple[int, int],
             is_goal: Callable[[tuple[int, int]], bool],
             turn: Optional[int] = None,
             health: int = 100) -> Optional[list[tuple[int, int]]]:
    if is_goal(start):
        return [start]
    G = state.map.graph
    visited = [[False] * state.map.y for _ in range(state.map.x)]
    queue: collections.deque = collections.deque()
    queue.append((start, [start], 0))
    shortest_path = 1000
    best_path = []
    best_damage = 1000
    while queue:
        (index_x, index_y), path, damage = queue.popleft()
        if visited[index_x][index_y]:
            continue
        if shortest_path != 1000 and len(path) >= shortest_path:
            break
        visited[index_x][index_y] = True
        index = state.map.pair_to_index(index_x, index_y)
        for neighbor, attrs in G[index].items():
            weight = attrs.get("weight", 0)
            nx, ny = state.map.index_to_pair(neighbor)
            new_path = path + [(nx, ny)]
            new_damage = damage + weight
            if (turn is not None and in_shrink_danger(Position(nx, ny), turn)) or new_damage >= health:
                continue
            if is_goal((nx, ny)):
                if shortest_path == 1000:
                    shortest_path = len(new_path)
                if best_damage > new_damage:
                    best_damage = new_damage
                    best_path = new_path
            queue.append(((nx, ny), new_path, new_damage))
    return best_path


def reachable_positions(state: GameState, me: Player) -> set[tuple[int, int]]:
    m = state.map
    idx = m.pair_to_index(me.position.x, me.position.y)
    if idx not in m.graph:
        return set()
    return {m.index_to_pair(n) for n in m.graph.neighbors(idx)}


def bfs_step_toward(state: GameState, me: Player,
                    is_goal: Callable[[tuple[int, int]], bool],
                    turn: int) -> Optional[tuple[int, int]]:
    path = bfs_path(state, (me.position.x, me.position.y), is_goal, turn=turn)
    return None if not path or len(path) < 2 else path[1]


def step_away_from(reachable: set[tuple[int, int]], me: Player,
                   target_xy: tuple[int, int], turn: int) -> Optional[tuple[int, int]]:
    pool = list(filter_safe(reachable, turn))
    if not pool:
        return None
    tx, ty = target_xy
    return max(pool, key=lambda xy: abs(xy[0] - tx) + abs(xy[1] - ty))


def dizzy_request_position(me_pos: Position, desired: tuple[int, int]) -> tuple[int, int]:
    rx = max(0, min(MAP_X - 1, 2 * me_pos.x - desired[0]))
    ry = max(0, min(MAP_Y - 1, 2 * me_pos.y - desired[1]))
    return (rx, ry)


# ===== inlined from bots/engine/helpers/combat.py =====
from typing import Optional




SPIKE_DAMAGE = 10


def can_summon_on(state: GameState, pos: Position, target_xy: tuple[int, int]) -> bool:
    tx, ty = target_xy
    if abs(tx - pos.x) + abs(ty - pos.y) != 1:
        return False
    t = tile_at(state.map, tx, ty)
    if t is None:
        return False
    if t.field_type in (FieldType.WALL, FieldType.EMPTY):
        return False
    return t.entity is None


def summon_targets(state: GameState, me: Player) -> list[tuple[int, int]]:
    return [xy for xy in orthogonal_neighbors(me.position) if can_summon_on(state, me.position, xy)]


def attackable_adjacent_enemy_tile(me: Player, enemy: Player) -> Optional[tuple[int, int]]:
    if not is_adjacent(me.position, enemy.position):
        return None
    return (enemy.position.x, enemy.position.y)


def attackable_adjacent_summon(state: GameState, me: Player, enemy: Optional[Player]) -> Optional[int]:
    if enemy is None:
        return None
    for nx, ny in orthogonal_neighbors(me.position):
        t = tile_at(state.map, nx, ny)
        if t and t.entity and t.entity.summoned_by == enemy.id:
            return t.entity.id
    return None


