from typing import Iterable, Optional




DEFAULT_X_PATTERN = [1, -1, 0, 0]
DEFAULT_Y_PATTERN = [0, 0, 1, -1]


def _patterns(entity) -> tuple[list[int], list[int]]:
    xp = entity.x_pattern or DEFAULT_X_PATTERN
    yp = entity.y_pattern or DEFAULT_Y_PATTERN
    n = min(len(xp), len(yp))
    return xp[:n], yp[:n]


def _is_fatigued(entity) -> bool:
    return entity.active_statuses.get(Status.Fatigue, 0) > 0


def entity_threat_tiles(entity, *, in_bounds_only: bool = True) -> set[tuple[int, int]]:
    rng = entity.attack_range or 0
    if rng < 1:
        return set()
    xp, yp = _patterns(entity)
    px, py = entity.position.x, entity.position.y
    out: set[tuple[int, int]] = set()
    for dx, dy in zip(xp, yp):
        for j in range(1, rng + 1):
            tx, ty = px + dx * j, py + dy * j
            if in_bounds_only and not in_bounds(tx, ty):
                break
            out.add((tx, ty))
    return out


def entity_threat_tiles_with_move(entity, *, in_bounds_only: bool = True) -> set[tuple[int, int]]:
    rng = entity.attack_range or 0
    if rng < 1:
        return set()
    xp, yp = _patterns(entity)
    move = max(0, entity.max_move_distance or 0)
    px, py = entity.position.x, entity.position.y
    out: set[tuple[int, int]] = set()
    for adx in range(-move, move + 1):
        rem = move - abs(adx)
        for ady in range(-rem, rem + 1):
            ax, ay = px + adx, py + ady
            for dx, dy in zip(xp, yp):
                for j in range(1, rng + 1):
                    tx, ty = ax + dx * j, ay + dy * j
                    if in_bounds_only and not in_bounds(tx, ty):
                        break
                    out.add((tx, ty))
    return out


def enemy_summons(state: GameState, me: Player, enemy: Optional[Player]) -> list[Entity]:
    out: list[Entity] = []
    for _, _, t in iter_cells(state.map):
        e = t.entity
        if e is None or e.summoned_by is None:
            continue
        if e.summoned_by == me.id:
            continue
        if e.health <= 0:
            continue
        out.append(e)
    return out


def threat_attackers(state: GameState, me: Player, enemy: Optional[Player],
                     include_player: bool = True) -> list[Entity]:
    attackers: list = [a for a in enemy_summons(state, me, enemy) if not _is_fatigued(a)]
    if include_player and enemy is not None and not _is_fatigued(enemy):
        attackers.append(enemy)
    return attackers


def threat_map(state: GameState, me: Player, enemy: Optional[Player], *,
               include_player: bool = True, with_move: bool = False) -> dict[tuple[int, int], int]:
    tiles_fn = entity_threat_tiles_with_move if with_move else entity_threat_tiles
    dmg: dict[tuple[int, int], int] = {}
    for a in threat_attackers(state, me, enemy, include_player=include_player):
        ap = a.attack_power or 0
        if ap <= 0:
            continue
        for tile in tiles_fn(a):
            dmg[tile] = dmg.get(tile, 0) + ap
    return dmg


def incoming_at(threat: dict[tuple[int, int], int], xy: tuple[int, int]) -> int:
    return threat.get(xy, 0)


