log = logging.getLogger("bot")


def legal(action: Action, ctx: RuleContext) -> bool:
    state, me, enemy = ctx.state, ctx.me, ctx.enemy

    if action.kind == "move":
        if action.target_x is None or action.target_y is None:
            return False
        reach = reachable_positions(state, me)
        if me.active_statuses.get(Status.Dizzy, 0) > 0:
            inv = dizzy_request_position(me.position, (action.target_x, action.target_y))
            return inv in reach
        return (action.target_x, action.target_y) in reach

    if action.kind == "attack":
        if action.target_id is None:
            return False
        if is_fatigued(me):
            return False
        target_pos = None
        target = state.players.get(str(action.target_id))
        if target is not None:
            target_pos = target.position
        else:
            for nx, ny in orthogonal_neighbors(me.position):
                t = tile_at(state.map, nx, ny)
                if t and t.entity and t.entity.id == action.target_id:
                    target_pos = Position(nx, ny)
                    break
        if target_pos is None or not is_adjacent(me.position, target_pos):
            return False
        return True

    if action.kind == "use_item":
        if action.item_id is None:
            return False
        return any(it.id == action.item_id for it in me.inventory)

    if action.kind == "pickup_item":
        if action.target_x is None or action.target_y is None:
            return False
        if not is_adjacent(me.position, Position(action.target_x, action.target_y)):
            return False
        t = tile_at(state.map, action.target_x, action.target_y)
        return t is not None and t.item is not None

    if action.kind == "pickup_card":
        if action.target_x is None or action.target_y is None:
            return False
        if not is_adjacent(me.position, Position(action.target_x, action.target_y)):
            return False
        t = tile_at(state.map, action.target_x, action.target_y)
        return t is not None and t.monster_card is not None

    if action.kind == "summon":
        if action.card_id is None or action.target_x is None or action.target_y is None:
            return False
        card = next((c for c in me.cards if c.id == action.card_id and not c.on_cooldown and (c.uses or 0) > 0), None)
        if card is None:
            return False
        return can_summon_on(state, me.position, (action.target_x, action.target_y))

    return False


class ActionExecutor:

    def __init__(self, server_url: str, game_id: str, timeout: float = 5.0):
        self.base = server_url.rstrip("/")
        self.game_id = game_id
        self.timeout = timeout

    _HEADERS = {"No-UI": "1"}

    def _put(self, path: str, body: Optional[dict] = None) -> requests.Response:
        return requests.put(f"{self.base}{path}", json=body, headers=self._HEADERS, timeout=self.timeout)

    def _get(self, path: str) -> requests.Response:
        return requests.get(f"{self.base}{path}", headers=self._HEADERS, timeout=self.timeout)

    def valid_moves(self, player_id: int) -> Optional[list]:
        try:
            r = self._get(f"/player/{player_id}/valid-moves/gameId/{self.game_id}")
            if 200 <= r.status_code < 300:
                return r.json()
        except requests.RequestException:
            pass
        return None

    def execute(self, action: Action, me: Player, state: Optional[GameState] = None) -> requests.Response:
        if action.kind == "move":
            tx, ty = action.target_x, action.target_y
            if me.active_statuses.get(Status.Dizzy, 0) > 0:
                tx, ty = dizzy_request_position(me.position, (tx, ty))
            return self._put(
                f"/player/move/gameId/{self.game_id}",
                {"playerId": me.id, "newPosition": {"X": tx, "Y": ty}},
            )
        if action.kind == "attack":
            return self._put(
                f"/player/{me.id}/attack/{action.target_id}/gameId/{self.game_id}"
            )
        if action.kind == "use_item":
            return self._put(
                f"/player/{me.id}/use-item/{action.item_id}/gameId/{self.game_id}"
            )
        if action.kind == "pickup_item":
            body = _field_info_body(state, action.target_x, action.target_y)
            return self._put(f"/player/pickup/{me.id}/gameId/{self.game_id}", body)
        if action.kind == "pickup_card":
            body = _field_info_body(state, action.target_x, action.target_y)
            return self._put(f"/map/pickup/{me.id}/gameId/{self.game_id}", body)
        if action.kind == "summon":
            return self._put(
                f"/map/{me.id}/summon/{action.card_id}/gameId/{self.game_id}",
                {"X": action.target_x, "Y": action.target_y},
            )
        raise ValueError(f"Unknown action kind: {action.kind}")


def _field_info_body(state: Optional[GameState], x: int, y: int) -> dict:
    if state is None:
        return {"Position": {"X": x, "Y": y}}
    cell = state.map.get_cell(x, y)
    if cell is None:
        return {"Position": {"X": x, "Y": y}}
    body = {
        "Position": {"X": x, "Y": y},
        "Entity": None,
        "FieldType": int(cell.field_type),
        "Owner": None,
        "Item": None,
        "MonsterCard": None,
        "Obstacle": None,
    }
    if cell.item is not None:
        body["Item"] = {
            "Id": cell.item.id,
            "Name": cell.item.name,
            "Uses": cell.item.uses,
            "Effect": cell.item.effect,
            "Range": cell.item.range,
            "Power": cell.item.power,
            "Duration": cell.item.duration,
            "ItemType": int(cell.item.item_type),
        }
    if cell.monster_card is not None:
        mc = cell.monster_card
        m = mc.monster
        body["MonsterCard"] = {
            "Id": mc.id,
            "Name": mc.name,
            "Uses": mc.uses,
            "Effect": mc.effect,
            "Power": mc.power,
            "OnCooldown": mc.on_cooldown,
            "Cooldown": mc.cooldown,
            "CooldownCounter": mc.cooldown_counter,
            "Monster": {
                "Id": m.id,
                "Name": m.name,
                "Health": m.health,
                "MaxHealth": m.max_health,
                "AttackPower": m.attack_power,
                "AttackRange": m.attack_range,
                "MaxMoveDistance": m.max_move_distance,
                "Position": {"X": m.position.x, "Y": m.position.y} if m.position else None,
                "SummonedByPlayerId": m.summoned_by,
                "xPattern": m.x_pattern,
                "yPattern": m.y_pattern,
            } if m is not None else None,
        }
    return body


def idle_pass_action(ctx: RuleContext) -> Optional[Action]:
    state, me = ctx.state, ctx.me

    cards_full = count_cards(me) >= 3
    freeze_full = count_freeze(me) >= 3

    for nx, ny in orthogonal_neighbors(me.position):
        t = tile_at(state.map, nx, ny)
        if t is None:
            continue
        if t.item is not None:
            item_name = (t.item.name or "").strip().lower()
            if item_name == ITEM_FREEZE_NAME.lower() and freeze_full:
                continue
            return Action(kind="pickup_item", target_x=nx, target_y=ny,
                          rule_name="idle_pickup_item")
        if t.monster_card is not None and not cards_full:
            return Action(kind="pickup_card", target_x=nx, target_y=ny,
                          rule_name="idle_pickup_card")

    reach = filter_safe(reachable_positions(state, me), ctx.turn)
    if reach:
        x, y = min(reach, key=lambda xy: abs(xy[0] - me.position.x) + abs(xy[1] - me.position.y))
        return Action(kind="move", target_x=x, target_y=y, rule_name="idle_move")

    if ctx.enemy is not None and not is_fatigued(me):
        return Action(kind="attack", target_id=ctx.enemy.id, rule_name="idle_attack_noop")

    return None


class Strategy:
    name: str = "Strategy"
    rules: list[Rule] = []

    def pick(self, ctx: RuleContext, rejected: Optional[set] = None, bot_logger: logging.Logger = None) -> Optional[Action]:
        rejection_reasons = []
        for rule in self.rules:
            try:
                action = rule(ctx)
            except Exception as e:
                bot_logger.info("rule %s raised %s — skipping", getattr(rule, "__name__", "?"), e)
                log.warning("rule %s raised %s — skipping", getattr(rule, "__name__", "?"), e)
                continue
            if isinstance(action, str):
                rejection_reasons.append(f"{getattr(rule, '__name__', '?')}: {action}")
                continue
            if action is None:
                bot_logger.info("rule %s returned None (no action) — skipping", getattr(rule, "__name__", "?"))
                continue
            if not action.rule_name:
                action.rule_name = getattr(rule, "__name__", "rule")
            if rejected and _action_key(action) in rejected:
                bot_logger.info("rule %s produced previously-rejected action %s — skipping", action.rule_name, action)
                log.debug("rule %s produced previously-rejected action — skipping", action.rule_name)
                continue
            if legal(action, ctx):
                if rejection_reasons and bot_logger:
                    bot_logger.info(_fmt_rejections(rejection_reasons))
                return action
            log.debug("rule %s produced illegal action %s — skipping", action.rule_name, action)
        if rejection_reasons and bot_logger:
            bot_logger.info(_fmt_rejections(rejection_reasons))
        idle = idle_pass_action(ctx)
        if idle is not None and legal(idle, ctx):
            return idle
        return None


def find_me(state: GameState, bot_name: str) -> Optional[Player]:
    for p in state.players.values():
        if p.name == bot_name:
            return p
    return None


def find_enemy(state: GameState, me: Player) -> Optional[Player]:
    for p in state.players.values():
        if p.id != me.id and p.summoned_by is None:
            return p
    return None


def is_my_turn(state: GameState, me: Player) -> bool:
    if me.first:
        return state.state_str == "Player1Turn"
    return state.state_str == "Player2Turn"


def run_bot(strategy: Strategy, server_url: str, game_id: str, bot_name: str,
            poll_interval: float = 0.5, max_idle_polls: int = 600) -> None:
    bot_log = logging.getLogger(f"bot.{bot_name}")
    if not bot_log.handlers:
        formatter = logging.Formatter(
            f"%(asctime)s [{bot_name}/{strategy.name}] %(message)s",
            datefmt="%H:%M:%S",
        )
        
        console_handler = logging.StreamHandler()
        console_handler.setFormatter(formatter)
        bot_log.addHandler(console_handler)
        
        safe_name = "".join(c for c in bot_name if c.isalnum() or c in ("_", "-")).rstrip()
        file_handler = logging.FileHandler(f"bot_actions_{safe_name}.log", mode="w", encoding="utf-8")
        file_handler.setFormatter(formatter)
        bot_log.addHandler(file_handler)
        
        bot_log.setLevel(logging.INFO)
        bot_log.propagate = False
        
    exec_ = ActionExecutor(server_url, game_id)
    base = server_url.rstrip("/")

    me: Optional[Player] = None
    state: Optional[GameState] = None
    waited = 0
    while me is None and waited < max_idle_polls:
        try:
            r = requests.get(f"{base}/game/state/{game_id}", headers={"No-UI": "1"}, timeout=5)
            if r.status_code == 200:
                state = parse_game_state(r.json())
                me = find_me(state, bot_name)
        except requests.RequestException as e:
            pass
        if me is None:
            time.sleep(poll_interval)
            veived_this_turn = waited + 1
    if me is None:
        bot_log.error("could not find player named %r in game %s", bot_name, game_id)
        return

    bot_log.info("connected as player %s (first=%s)", me.id, me.first)
    last_turn_acted = -1
    rejected_this_turn: set[tuple] = set()
    card_cooldown_block: dict[int, int] = {}

    while True:
        try:
            r = requests.get(f"{base}/game/state/{game_id}", headers={"No-UI": "1"}, timeout=5)
            if r.status_code != 200:
                time.sleep(poll_interval)
                continue
            state = parse_game_state(r.json())
        except requests.RequestException as e:
            time.sleep(poll_interval)
            continue

        if state.state_str == "Ending":
            bot_log.info("game ended at turn %s", state.current_turn)
            return

        me = find_me(state, bot_name)
        if me is None:
            bot_log.warning("lost player record; retrying")
            time.sleep(poll_interval)
            continue

        if not is_my_turn(state, me):
            time.sleep(poll_interval)
            continue

        if state.current_turn == last_turn_acted and state.state_str == ("Player1Turn" if me.first else "Player2Turn"):
            time.sleep(poll_interval)
            continue

        if state.current_turn != last_turn_acted:
            rejected_this_turn.clear()
        for cid, unblock_turn in list(card_cooldown_block.items()):
            if state.current_turn < unblock_turn:
                rejected_this_turn.add(("summon", cid))
            else:
                del card_cooldown_block[cid]

        enemy = find_enemy(state, me)
        ctx = RuleContext(state=state, me=me, enemy=enemy, turn=state.current_turn)

        action = strategy.pick(ctx, rejected=rejected_this_turn, bot_logger=bot_log)
        if action is None:
            bot_log.warning("turn %s: no legal action found — yielding turn to server timeout", state.current_turn)
            time.sleep(poll_interval)
            continue
        pos = f"({me.position.x},{me.position.y})"
        hp  = f"hp={me.health}"
        en_str = (f"  vs  en@({enemy.position.x},{enemy.position.y}) hp={enemy.health}"
                  if enemy else "  no enemy")
        bot_log.info("T%02d | me@%s %s%s | %s  [%s]",
                     state.current_turn, pos, hp, en_str, _describe(action), action.rule_name)
        try:
            resp = exec_.execute(action, me, state)
            if action.kind in ("pickup_card", "pickup_item"):
                bot_log.debug("pickup(%s,%s) http=%s", action.target_x, action.target_y, resp.status_code)
            if 200 <= resp.status_code < 300:
                last_turn_acted = state.current_turn
            elif resp.status_code == 409:
                bot_log.error("turn locked out (409) — stopping")
                return
            elif resp.status_code == 400:
                err = resp.text or ""
                if _is_server_crash(err):
                    bot_log.warning("server crash post-action (%s) — action was processed, continuing", action.kind)
                    last_turn_acted = state.current_turn
                else:
                    bot_log.warning("action rejected (400): %s", err[:200])
                    rejected_this_turn.add(_action_key(action))
                    if action.kind == "summon" and action.card_id is not None:
                        card = next((c for c in me.cards if c.id == action.card_id), None)
                        cooldown = card.cooldown if card else 7
                        unblock_at = state.current_turn + cooldown + 1
                        card_cooldown_block[action.card_id] = max(
                            card_cooldown_block.get(action.card_id, 0), unblock_at
                        )
                        bot_log.warning("card %s blocked until turn %s", action.card_id, unblock_at)
            else:
                bot_log.warning("unexpected status (%s): %s", resp.status_code, resp.text)
        except requests.RequestException as e:
            bot_log.warning("PUT failed: %s", e)

        time.sleep(poll_interval)


def _fmt_rejections(reasons: list[str]) -> str:
    lines = ["  skipped:"]
    for r in reasons:
        name, sep, msg = r.partition(": ")
        parts = name.split("_", 2)
        short = parts[2] if len(parts) == 3 and parts[1].isdigit() else name
        lines.append(f"    x {short}: {msg}" if sep else f"    x {r}")
    return "\n".join(lines)


def _is_server_crash(body: str) -> bool:
    return any(marker in body for marker in ("System.", "at Server.", "Collection was modified"))


def _action_key(a: Action) -> tuple:
    if a.kind == "summon":
        return ("summon", a.card_id)
    return (a.kind, a.target_id, a.card_id, a.item_id, a.target_x, a.target_y)


def _describe(a: Action) -> str:
    if a.kind == "move":
        return f"move({a.target_x},{a.target_y})"
    if a.kind == "attack":
        return f"attack(id={a.target_id})"
    if a.kind == "use_item":
        return f"use_item(id={a.item_id})"
    if a.kind == "pickup_item":
        return f"pickup_item({a.target_x},{a.target_y})"
    if a.kind == "pickup_card":
        return f"pickup_card({a.target_x},{a.target_y})"
    if a.kind == "summon":
        return f"summon(card={a.card_id} at {a.target_x},{a.target_y})"
    return a.kind


