from typing import Optional, Union



def r1_1_lethal_kill(ctx: RuleContext) -> Union[Action, str]:
    me, enemy = ctx.me, ctx.enemy
    if enemy is None or is_fatigued(me):
        return "No enemy or player is fatigued"
    if attackable_adjacent_enemy_tile(me, enemy) is None:
        return "Enemy not in valid adjacent attack position"
    if me.attack_power < enemy.health:
        return "Attack power insufficient for lethal"
    return Action(kind="attack", target_id=enemy.id, rule_name="R1.1_lethal_kill")


def r1_2_shrink_escape(ctx: RuleContext) -> Union[Action, str]:
    me, enemy = ctx.me, ctx.enemy
    if not in_shrink_danger(me.position, ctx.turn):
        return "Not in shrink danger zone"
    reach = reachable_positions(ctx.state, me)
    safe = filter_safe(reach, ctx.turn)
    if not safe:
        return "No safe reachable positions available"
    def key(xy):
        d_self = abs(xy[0] - me.position.x) + abs(xy[1] - me.position.y)
        d_enemy = (abs(xy[0] - enemy.position.x) + abs(xy[1] - enemy.position.y)
                   if enemy is not None else 0)
        return (d_self, -d_enemy)
    x, y = min(safe, key=key)
    return Action(kind="move", target_x=x, target_y=y, rule_name="R1.2_shrink_escape")


def r1_3_heal_or_die(ctx: RuleContext) -> Union[Action, str]:
    me, enemy = ctx.me, ctx.enemy
    if enemy is None:
        return "No enemy threat detected"
    if me.health > enemy.attack_power + SPIKE_DAMAGE:
        return "Health sufficient to survive next hit"
    heal = find_item_by_name(me, ITEM_HEAL_NAME)
    if heal is not None:
        return Action(kind="use_item", item_id=heal.id, rule_name="R1.3_heal_use")
    tile = adjacent_item_tile(ctx.state, me, item_name=ITEM_HEAL_NAME)
    if tile is not None:
        return Action(kind="pickup_item", target_x=tile[0], target_y=tile[1],
                      rule_name="R1.3_heal_pickup")
    return "No heal items available (using none)"


def r1_4_use_dizzy_scroll(ctx: RuleContext) -> Union[Action, str]:
    me, enemy = ctx.me, ctx.enemy
    if enemy is None:
        return "No enemy detected"
    item = find_item_by_name(me, ITEM_DIZZY_NAME)
    if item is None:
        return "No dizzy scroll in inventory"
    if has_status(enemy, Status.Dizzy) or has_status(enemy, Status.Frozen):
        return "Enemy already dizzy or frozen"
    rng = item.range if item.range is not None else 3
    if manhattan(me.position, enemy.position) > rng:
        return "Enemy out of dizzy scroll range"
    return Action(kind="use_item", item_id=item.id, rule_name="R1.4_use_dizzy")


def r_attack_enemy_summon(ctx: RuleContext) -> Union[Action, str]:
    me, enemy = ctx.me, ctx.enemy
    if enemy is None or is_fatigued(me):
        return "No enemy or player is fatigued"
    summon_id = attackable_adjacent_summon(ctx.state, me, enemy)
    if summon_id is None:
        return "No attackable adjacent enemy summon found"
    return Action(kind="attack", target_id=summon_id, rule_name="R_attack_enemy_summon")


SHARED_TOP: list = [r1_1_lethal_kill, r1_2_shrink_escape, r1_3_heal_or_die, r1_4_use_dizzy_scroll]
SHARED_BOTTOM: list = [r_attack_enemy_summon]


# ===== inlined from bots/strategies/hunter/rules_hunter.py =====
import math
from typing import Callable, Optional, Union



CARD_VALUE_ICE_CUBE = 25.0
CARD_VALUE_MAGE     = 70.0
CARD_VALUE_WARRIOR  = 60.0

ITEM_VALUE_HEAL     = 20.0
ITEM_VALUE_FREEZE   = 12.0

MY_DIST_PENALTY  = 0.3
ENEMY_PROX_BONUS = 0.2

GRAVE_DANGER_BUFFER = 21
COMMIT_TO_GOAL_BUFFER = 15

LATE_GAME_TURN           = 100
LATE_GAME_HEAL_THRESHOLD = 100

MAX_FREEZE_STACK = 3
MAX_HEAL_STACK   = 3
MAX_CARD_HAND    = 3

MAP_CENTER_X  = 15.5
MAP_CENTER_Y  = 7.5
_MAP_MAX_DIST = MAP_CENTER_X + MAP_CENTER_Y
CENTER_BONUS  = 0.15

ITEM_REFRESH_TURNS = 20
REFRESH_VALUE      = 100.0
REFRESH_LOOKAHEAD  = 6


_bfs_cache: dict = {}
_bfs_cache_now: int = -1


def _bfs_adj(
    state,
    start: tuple[int, int],
    gx: int,
    gy: int,
    turn_filter: Optional[int],
    now: int,
    health: int
) -> Optional[list[tuple[int, int]]]:
    def is_adj(pos: tuple, _gx: int = gx, _gy: int = gy) -> bool:
        return abs(pos[0] - _gx) + abs(pos[1] - _gy) == 1
    if turn_filter is not None:
        result = bfs_path(state, start, is_adj, turn=turn_filter, health=health)
    else:
        result = bfs_path(state, start, is_adj, health=health)

    return result if result else None


def _card_tile_base_value(monster_card) -> float:
    if _is_ice_cube_card(monster_card):
        return CARD_VALUE_ICE_CUBE
    if (monster_card.power or 0) >= 35:
        return CARD_VALUE_MAGE
    return CARD_VALUE_WARRIOR


def _item_tile_base_value(item) -> float:
    name = (item.name or "").strip().lower()
    if name == ITEM_HEAL_NAME.strip().lower():
        return ITEM_VALUE_HEAL
    if name == ITEM_FREEZE_NAME.strip().lower():
        return ITEM_VALUE_FREEZE
    return 0.0


def _turns_for_path(path: list[tuple[int, int]]) -> int:
    return len(path) - 1


def _find_best_goal(
    ctx: RuleContext,
) -> tuple[Optional[tuple[int, int]], Optional[list[tuple[int, int]]]]:
    me, enemy = ctx.me, ctx.enemy
    my_pos = (me.position.x, me.position.y)
    enemy_pos = (enemy.position.x, enemy.position.y) if enemy else None

    best_score = -1.0
    best_goal: Optional[tuple[int, int]] = None
    best_path: Optional[list[tuple[int, int]]] = None

    fb_score = -1.0
    fb_goal: Optional[tuple[int, int]] = None
    fb_path: Optional[list[tuple[int, int]]] = None

    for gx, gy, t in iter_cells(ctx.state.map):
        if t.monster_card is None and t.item is None:
            continue
        if abs(gx - me.position.x) + abs(gy - me.position.y) <= 1:
            continue
        if t.monster_card is not None:
            uses = t.monster_card.uses or 1
            base_value = _card_tile_base_value(t.monster_card) * (uses + 1) / 2
            if count_cards(me) >= MAX_CARD_HAND:
                continue
        else:
            base_value = _item_tile_base_value(t.item)
            if base_value == 0.0:
                continue
            name_lc = (t.item.name or "").strip().lower()
            if name_lc == ITEM_FREEZE_NAME.strip().lower():
                if count_freeze(me) >= MAX_FREEZE_STACK:
                    continue
            elif name_lc == ITEM_HEAL_NAME.strip().lower():
                if count_heal(me) >= MAX_HEAL_STACK:
                    continue

        my_path = _bfs_adj(ctx.state, my_pos, gx, gy, turn_filter=ctx.turn, now=ctx.turn, health=ctx.me.health)
        if not my_path:
            continue
        my_turns = _turns_for_path(my_path)

        if enemy is not None and find_item_by_name(me, ITEM_HEAL_NAME) is None:
            if _path_damage_estimate(ctx, my_path) >= me.health:
                continue

        center_dist = abs(gx - MAP_CENTER_X) + abs(gy - MAP_CENTER_Y)
        center_factor = 1.0 + CENTER_BONUS * (1.0 - center_dist / _MAP_MAX_DIST)

        fb_raw = base_value * center_factor / (1.0 + my_turns * MY_DIST_PENALTY)
        if fb_raw > fb_score:
            fb_score = fb_raw
            fb_goal = (gx, gy)
            fb_path = my_path

        enemy_turns: Optional[int] = None
        if enemy_pos is not None:
            enemy_path = _bfs_adj(ctx.state, enemy_pos, gx, gy, turn_filter=None, now=ctx.turn, health=ctx.me.health)
            if enemy_path is not None:
                enemy_turns = _turns_for_path(enemy_path)
                if my_turns > enemy_turns:
                    continue

        prox = (1.0 + enemy_turns * ENEMY_PROX_BONUS) if enemy_turns is not None else 1.0
        score = base_value * center_factor / (1.0 + my_turns * MY_DIST_PENALTY) * prox

        if score > best_score:
            best_score = score
            best_goal = (gx, gy)
            best_path = my_path

    turns_until_refresh = ITEM_REFRESH_TURNS - (ctx.turn % ITEM_REFRESH_TURNS)
    if turns_until_refresh <= REFRESH_LOOKAHEAD:
        for cgx, cgy in [(15, 7), (16, 7), (15, 8), (16, 8)]:
            c_path = _bfs_adj(ctx.state, my_pos, cgx, cgy,
                              turn_filter=ctx.turn, now=ctx.turn, health=me.health)
            if not c_path:
                continue
            effective_turns = _turns_for_path(c_path) + turns_until_refresh
            r_score = REFRESH_VALUE / (1.0 + effective_turns * MY_DIST_PENALTY)
            if r_score > best_score:
                best_score = r_score
                best_goal = (cgx, cgy)
                best_path = c_path
            if r_score > fb_score:
                fb_score = r_score
                fb_goal = (cgx, cgy)
                fb_path = c_path
            break

    if best_goal is not None:
        return best_goal, best_path
    return fb_goal, fb_path


def _path_damage_estimate(ctx: RuleContext, path: list[tuple[int, int]]) -> int:
    if ctx.enemy is None:
        return 0
    t_map = threat_map(ctx.state, ctx.me, ctx.enemy, include_player=True)
    return sum(t_map.get(pos, 0) for pos in path[1:])


def _off_path_targets(ctx: RuleContext, all_targets: list) -> list:
    _, plan_path = _find_best_goal(ctx)
    if not plan_path:
        return all_targets
    path_set = set(plan_path)
    off_path = [xy for xy in all_targets if xy not in path_set]
    return off_path if off_path else all_targets


def _enemy_goal_path(ctx: RuleContext) -> Optional[list[tuple[int, int]]]:
    enemy = ctx.enemy
    if enemy is None:
        return None
    enemy_pos = (enemy.position.x, enemy.position.y)

    best_score = -1.0
    best_path: Optional[list[tuple[int, int]]] = None

    for gx, gy, t in iter_cells(ctx.state.map):
        if t.monster_card is None and t.item is None:
            continue
        if t.monster_card is not None:
            base_value = _card_tile_base_value(t.monster_card)
        else:
            base_value = _item_tile_base_value(t.item)
            if base_value == 0.0:
                continue

        enemy_path = _bfs_adj(ctx.state, enemy_pos, gx, gy, turn_filter=None, now=ctx.turn, health=ctx.me.health)
        if enemy_path is None:
            continue
        center_dist = abs(gx - MAP_CENTER_X) + abs(gy - MAP_CENTER_Y)
        center_factor = 1.0 + CENTER_BONUS * (1.0 - center_dist / _MAP_MAX_DIST)
        score = base_value * center_factor / (1.0 + _turns_for_path(enemy_path) * MY_DIST_PENALTY)
        if score > best_score:
            best_score = score
            best_path = enemy_path

    return best_path


def w1_1_cornered_heal(ctx: RuleContext) -> Union[Action, str]:
    me, enemy = ctx.me, ctx.enemy
    if enemy is None:
        return "No enemy"

    my_xy = (me.position.x, me.position.y)
    t_map = threat_map(ctx.state, me, enemy, include_player=True)
    incoming = t_map.get(my_xy, 0)

    if me.health > incoming + SPIKE_DAMAGE + GRAVE_DANGER_BUFFER:
        return "Not in grave danger"
    if incoming <= 0:
        return "No incoming damage on current tile"

    heal = find_item_by_name(me, ITEM_HEAL_NAME)
    if heal is None:
        return "No heal in inventory"

    reach = filter_safe(reachable_positions(ctx.state, me), ctx.turn)
    retreat = step_away_from(reach, me, (enemy.position.x, enemy.position.y), ctx.turn)
    
    if (incoming <= 25 or retreat is None) and ctx.me.health < GRAVE_DANGER_BUFFER:
        return Action(kind="use_item", item_id=heal.id, rule_name="W1.1_cornered_heal")

    return "Retreat possible, prefer fleeing to healing"

def w1_2_freeze_into_shrink(ctx: RuleContext) -> Union[Action, str]:
    me, enemy = ctx.me, ctx.enemy
    if enemy is None or not has_freeze(me):
        return "No enemy or no freeze items"
    turn = ctx.turn
    if turn >= 45:
        return "No more shrinks remaining"
    next_shrink = 15 if turn < 15 else 30 if turn < 30 else 45
    if not in_shrink_danger(enemy.position, turn):
        return "Enemy not in shrink danger zone"
    turns_until = next_shrink - turn
    if count_freeze(me) * 2 < turns_until:
        return "Not enough freezes to cover until shrink fires"
    current_frozen = enemy.active_statuses.get(Status.Frozen, 0)
    if current_frozen >= turns_until:
        return "Enemy already frozen long enough to die in shrink"
    item = find_item_by_name(me, ITEM_FREEZE_NAME)
    if item is None:
        return "Freeze item not found"
    return Action(kind="use_item", item_id=item.id, rule_name="W1.2_freeze_into_shrink")


def w1_3_late_game_heal(ctx: RuleContext) -> Union[Action, str]:
    me = ctx.me
    if ctx.turn <= LATE_GAME_TURN - count_heal(me):
        return "Not late game yet"
    if me.health >= LATE_GAME_HEAL_THRESHOLD:
        return "HP already high enough"
    heal = find_item_by_name(me, ITEM_HEAL_NAME)
    if heal is None:
        return "No heal in inventory"
    return Action(kind="use_item", item_id=heal.id, rule_name="W1.3_late_game_heal")


def w1_4_attack_enemy_player(ctx: RuleContext) -> Union[Action, str]:
    me, enemy = ctx.me, ctx.enemy
    if enemy is None:
        return "No enemy"
    if is_fatigued(me):
        return "We are fatigued"
    if not is_adjacent(me.position, enemy.position):
        return "Enemy not adjacent"

    my_dmg = me.attack_power
    for nx, ny in orthogonal_neighbors(enemy.position):
        t = tile_at(ctx.state.map, nx, ny)
        if t and t.entity and t.entity.summoned_by == me.id and not is_fatigued(t.entity):
            my_dmg += t.entity.attack_power

    t_map = threat_map(ctx.state, me, enemy, include_player=True)
    their_dmg = t_map.get((me.position.x, me.position.y), 0)

    if my_dmg <= their_dmg:
        return f"Enemy out-damages us ({their_dmg} vs {my_dmg})"
    if me.health <= their_dmg:
        return "Cannot survive incoming damage"

    return Action(kind="attack", target_id=enemy.id, rule_name="W1.4_attack_enemy_player")


def _blocking_summon_target(ctx: RuleContext, all_targets: list) -> Optional[tuple[int, int]]:
    ep = _enemy_goal_path(ctx)
    if not ep:
        return None
    path_index = {(x, y): i for i, (x, y) in enumerate(ep)}
    blocking = [(path_index[xy], xy) for xy in all_targets if xy in path_index]
    if not blocking:
        return None
    _, best = max(blocking)
    return best


def _pick_summon_target(ctx: RuleContext, all_targets: list) -> tuple[int, int]:
    block = _blocking_summon_target(ctx, all_targets)
    if block is not None:
        return block
    targets = _off_path_targets(ctx, all_targets)
    enemy = ctx.enemy
    if enemy is not None:
        ex, ey = enemy.position.x, enemy.position.y
        return min(targets, key=lambda xy: abs(xy[0] - ex) + abs(xy[1] - ey))
    return targets[0]


def w2_1_freeze_into_summon_pattern(ctx: RuleContext) -> Union[Action, str]:
    me, enemy = ctx.me, ctx.enemy
    if enemy is None or not has_freeze(me):
        return "No enemy or no freeze items"

    enemy_xy = (enemy.position.x, enemy.position.y)
    allied = find_allied_summons(ctx.state, me)
    if not any(enemy_xy in entity_threat_tiles_with_move(s) for s in allied):
        return "Enemy not in any allied summon's strike pattern"

    if enemy.active_statuses.get(Status.Frozen, 0) >= 2:
        return "Enemy already frozen 2+ turns"
    item = find_item_by_name(me, ITEM_FREEZE_NAME)
    if item is None:
        return "Freeze item not found"
    return Action(kind="use_item", item_id=item.id, rule_name="W2.1_freeze_into_summon_pattern")


def w2_2_summon_warrior(ctx: RuleContext) -> Union[Action, str]:
    me = ctx.me
    cards = available_warrior_cards(me)
    if not cards:
        return "No warrior cards available"
    all_targets = summon_targets(ctx.state, me)
    if not all_targets:
        return "No summon targets"
    tx, ty = _pick_summon_target(ctx, all_targets)
    return Action(kind="summon", card_id=pick_card_max_uses(cards).id, target_x=tx, target_y=ty,
                  rule_name="W2.2_summon_warrior")


