def w3_1_kill_adjacent_mob(ctx: RuleContext) -> Union[Action, str]:
    me, enemy = ctx.me, ctx.enemy
    if enemy is None:
        return "No enemy"
    if is_fatigued(me):
        return "We are fatigued"
    if is_adjacent(me.position, enemy.position):
        return "Enemy player also adjacent — skip mob"
    mobs = [
        t.entity
        for nx, ny in orthogonal_neighbors(me.position)
        if (t := tile_at(ctx.state.map, nx, ny)) and t.entity
        and t.entity.summoned_by == enemy.id
    ]
    if not mobs:
        return "No adjacent enemy mobs"
    if len(mobs) > 1:
        return "Multiple mobs adjacent"
    mob = mobs[0]
    if not me.attack_power:
        return "Zero attack power"
    turns_to_kill = math.ceil(mob.health / me.attack_power)
    if turns_to_kill > 2:
        return "Cannot kill mob within 2 turns"
    total_incoming = turns_to_kill * mob.attack_power
    if me.health <= total_incoming + COMMIT_TO_GOAL_BUFFER:
        return "Not enough HP to survive mob fight"
    return Action(kind="attack", target_id=mob.id, rule_name="W3.1_kill_adjacent_mob")


def w4_1_pickup_warrior_card(ctx: RuleContext) -> Union[Action, str]:
    me = ctx.me
    if len(me.cards) >= MAX_CARD_HAND:
        return "Hand full"
    for nx, ny in orthogonal_neighbors(me.position):
        t = tile_at(ctx.state.map, nx, ny)
        if t and t.monster_card and _is_warrior_card(t.monster_card):
            return Action(kind="pickup_card", target_x=nx, target_y=ny,
                          rule_name="W4.1_pickup_warrior_card")
    return "No adjacent warrior card"


